  ('diplomatic-ea72210e-moex-00270', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-112-bf235e6a', 'sub-diplomatic-ea72210e-06', NULL, 'single_choice', '臺灣的新聞鮮少登上國際媒體，但是2021年臺灣的「鮭魚之亂」與「太魯閣號出軌」新聞事件被 國際媒體大幅報導。下列那一個國際傳播的術語最適切捕捉此種情況？', '["非平衡之新聞流通", "新聞價值", "新聞形象", "新聞框架"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:39+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00271', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-112-bf235e6a', 'sub-diplomatic-ea72210e-06', NULL, 'single_choice', '日本學者岩淵功一提出下列那一個概念，用來修正文化接近性的理論觀點？', '["文化混雜", "文化趨近", "文化折扣", "文化共鳴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:39+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00272', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-112-bf235e6a', 'sub-diplomatic-ea72210e-06', NULL, 'single_choice', '英國社會學家紀登斯（AnthonyGiddens）認為全球化趨勢是現代性的結果之一，而全球化包含的 四個面向不包括下列何者？', '["世界軍事秩序", "國際勞動分工", "社會關係治理", "國族國家體系"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:39+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00273', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-112-bf235e6a', 'sub-diplomatic-ea72210e-06', NULL, 'single_choice', '有關公眾外交的說明，下列敘述何者錯誤？', '["長期公眾外交的目標，是希望在國際社會中提高支持度，以獲取單一政治倡議（political advocacy）的成功", "對政府而言，公眾外交的目標之一，是希望其外交政策也能獲得國內民眾的支持", "推動公眾外交，會盡量避免被貼上宣傳（propaganda）的標籤，以免造成負面印象", "美國在冷戰時期的公眾外交主軸，是說服歐洲民眾美利堅式民主與資本主義體制優於蘇維埃式 政治體制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:39+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00274', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-112-bf235e6a', 'sub-diplomatic-ea72210e-06', NULL, 'single_choice', '數位匯流時代，社群媒體平台也能扮演國際傳播的有效機制。有關澳洲政府要求平台業者付費給 新聞業者一事，下列敘述何者錯誤？', '["澳洲已通過「平台公平付費法案」，要求Facebook與Google等平台業者應與新聞業者拆分內容 收益", "Google與澳洲各大媒體業者針對「付費」已達成合作協議", "Facebook一度封鎖澳洲的使用者讀取或分享澳洲新聞內容，封鎖對象也包括境外的使用者", "Facebook封鎖澳洲新聞期間，非關新聞的政府組織或慈善團體網頁也陰錯陽差遭到封鎖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:39+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00275', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-112-bf235e6a', 'sub-diplomatic-ea72210e-06', NULL, 'single_choice', '於2013年正式在美國市場開播的半島電視臺，是透過何種策略進入？', '["成為有線電視系統業者", "併購美國有線電視頻道", "成立衛星電視臺", "提供網路串流服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:39+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
