  ('diplomatic-ea72210e-moex-00278', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-112-bf235e6a', 'sub-diplomatic-ea72210e-06', NULL, 'single_choice', '有關「隨選訂閱（subscriptionvideoondemand,SVOD)」與「網路播放影音服務（over-the-topservices, OTT）」開始盛行，下列敘述何者錯誤？', '["SVOD與OTT提供精準的推薦機制，讓閱聽人得以接觸到自己偏好的內容", "根據「閱聽人商品理論」，SVOD與OTT因為沒有廣告內容，因此閱聽人得以逃脫勞動剝削", "SVOD與OTT提供推薦機制的精準度，有賴蒐集大量使用者的數位足跡資料", "SVOD與OTT業者會委託數據分析公司蒐集社群媒體上的談論資料，作為生產與編排節目的 依據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:39+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00279', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-112-bf235e6a', 'sub-diplomatic-ea72210e-06', NULL, 'single_choice', '英國社會學家 Alan Bryman（2004）用下列那一概念來批判全球商業化轉變時，所有的商品或環 境都變成過度簡化、高度控制與重度倚賴情緒勞動？', '["麥當勞化", "福特主義", "迪士尼化", "星巴克化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:39+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL)
